extra.modelCss:
/* Tema completo (tokens) + componentes base */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --danger: #ef4444;
  --success: #22c55e;

  --border: rgba(255, 255, 255, 0.10);
  --radius: 14px;

  --shadow-1: 0 6px 16px rgba(0, 0, 0, 0.12);
  --shadow-2: 0 16px 40px rgba(0, 0, 0, 0.16);

  --space-1: 8px;
  --space-2: 12px;
  --space-3: 16px;
  --space-4: 24px;

  --font-sans: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  --font-mono: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-sans);
  line-height: 1.6;
}

.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: var(--space-3);
}

@media (min-width: 768px) {
  .container { padding: var(--space-4); }
}

.stack {
  display: grid;
  gap: var(--space-3);
}

.muted {
  color: var(--muted);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, opacity 150ms ease;
}

.btn:hover {
  transform: translateY(-1px);
  opacity: 0.95;
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.btn.primary {
  background: var(--accent);
  color: #0b0f19;
}

.btn.ghost {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

.btn.danger {
  background: var(--danger);
  color: #0b0f19;
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
  transform: none;
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-1);
}

.card-inner {
  padding: var(--space-3);
  display: grid;
  gap: 10px;
}

.input {
  width: 100%;
  padding: 10px 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.02);
  color: var(--text);
  font-family: var(--font-sans);
}

.input:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 2px;
  border-color: rgba(96, 165, 250, 0.60);
}

.input-error {
  border-color: var(--danger);
}

.input-success {
  border-color: var(--success);
}

@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    animation: none !important;
  }
}
